-- Dedicated Old Slavonic alphabet entity for the church content system,
-- mirroring church_saints: per-language rows linked by translation group.
-- Replaces the hardcoded letters array previously baked into the frontend
-- (components/site/SlavonicAlphabetPage.tsx).

CREATE TABLE IF NOT EXISTS church_alphabet_letters (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    site_id UUID NOT NULL REFERENCES sites(id),
    slug TEXT NOT NULL,
    letter TEXT NOT NULL,
    sort_order INTEGER NOT NULL DEFAULT 0,
    name TEXT NOT NULL,
    short_description TEXT NOT NULL DEFAULT '',
    full_text TEXT NOT NULL DEFAULT '',
    numeric_value INTEGER,
    modern_equivalent TEXT NOT NULL DEFAULT '',
    color TEXT NOT NULL DEFAULT '',
    card_image_url TEXT NOT NULL DEFAULT '',
    main_image_url TEXT NOT NULL DEFAULT '',
    seo_title TEXT NOT NULL DEFAULT '',
    seo_description TEXT NOT NULL DEFAULT '',
    language TEXT NOT NULL DEFAULT 'uk',
    translation_group_id UUID NOT NULL DEFAULT gen_random_uuid(),
    status TEXT NOT NULL DEFAULT 'draft',
    is_global BOOLEAN NOT NULL DEFAULT FALSE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT church_alphabet_language_check CHECK (language IN ('uk', 'ru', 'en')),
    CONSTRAINT church_alphabet_status_check CHECK (status IN ('draft', 'published', 'archived')),
    CONSTRAINT church_alphabet_site_slug_language_unique UNIQUE (site_id, slug, language)
);

CREATE INDEX IF NOT EXISTS idx_church_alphabet_site_status
    ON church_alphabet_letters(site_id, status, sort_order);
CREATE INDEX IF NOT EXISTS idx_church_alphabet_translation_group
    ON church_alphabet_letters(translation_group_id, language);

DROP TRIGGER IF EXISTS church_alphabet_letters_set_updated_at ON church_alphabet_letters;
CREATE TRIGGER church_alphabet_letters_set_updated_at
    BEFORE UPDATE ON church_alphabet_letters
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

